using Valve.VR;

namespace FloatSoda.Exceptions;

public class VrInitialException(string message, EVRInitError errorCode) : OpenVrException<EVRInitError>(message, errorCode);

public static class VrInitialExceptionValidator
{
    public static void ThrowIfError(this EVRInitError error)
    {
        if (error == EVRInitError.None) return;

        throw error switch {
            // --- 一般的な初期化エラー ---
            EVRInitError.Unknown => new VrInitialException("未知の初期化エラーが発生しました。", error),
            EVRInitError.Init_InstallationNotFound => new VrInitialException("OpenVRのインストールが見つかりません。", error),
            EVRInitError.Init_InstallationCorrupt => new VrInitialException("OpenVRのインストールが壊れています。", error),
            EVRInitError.Init_VRClientDLLNotFound => new VrInitialException("vrclient.dllが見つかりません。", error),
            EVRInitError.Init_FileNotFound => new VrInitialException("必要な構成ファイルが見つかりません。", error),
            EVRInitError.Init_FactoryNotFound => new VrInitialException("ファクトリインターフェースの取得に失敗しました。", error),
            EVRInitError.Init_InterfaceNotFound => new VrInitialException("要求されたインターフェースが見つかりません。", error),
            EVRInitError.Init_InvalidInterface => new VrInitialException("インターフェースが無効です。", error),
