            EVRInitError.Init_PathRegistryNotWritable => new VrInitialException("パスレジストリに書き込めません。", error),
            EVRInitError.Init_AppInfoInitFailed => new VrInitialException("アプリケーション情報の初期化に失敗しました。", error),
            EVRInitError.Init_Retry => new VrInitialException("再試行が必要です。", error),
